-- Table structure for table `t_order_reconciliation_approval`
--

DROP TABLE IF EXISTS `t_order_reconciliation_approval`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `t_order_reconciliation_approval` (
  `id` varchar(32) NOT NULL COMMENT '主键ID',
  `factory_name` varchar(100) NOT NULL COMMENT '工厂名称（本厂或加工厂名）',
  `is_own_factory` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否本厂(0:加工厂, 1:本厂)',
  `order_count` int DEFAULT '0' COMMENT '订单数量',
  `total_quantity` int DEFAULT '0' COMMENT '总件数',
  `total_amount` decimal(15,2) DEFAULT '0.00' COMMENT '总金额',
  `reconciliation_ids` text COMMENT '关联的结算单ID列表（逗号分隔）',
  `status` varchar(20) DEFAULT 'pending' COMMENT '状态(pending:待审核, verified:已验证, approved:已批准, paid:已付款, rejected:已拒绝)',
  `approval_time` datetime DEFAULT NULL COMMENT '批准时间',
  `approval_by` varchar(50) DEFAULT NULL COMMENT '批准人',
  `payment_time` datetime DEFAULT NULL COMMENT '付款时间',
  `payment_by` varchar(50) DEFAULT NULL COMMENT '付款人',
  `payment_method` varchar(50) DEFAULT NULL COMMENT '付款方式（银行转账/现金/微信/支付宝）',
  `re_review_time` datetime DEFAULT NULL COMMENT '重审时间',
  `re_review_reason` text COMMENT '重审原因',
  `remark` text COMMENT '备注',
  `create_time` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `create_by` varchar(50) DEFAULT NULL COMMENT '创建人',
  `update_by` varchar(50) DEFAULT NULL COMMENT '更新人',
  PRIMARY KEY (`id`),
  KEY `idx_factory_name` (`factory_name`),
  KEY `idx_status` (`status`),
  KEY `idx_is_own_factory` (`is_own_factory`),
  KEY `idx_create_time` (`create_time`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='订单结算审批付款表';
