DROP TABLE IF EXISTS `t_pattern_revision`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `t_pattern_revision` (
  `id` varchar(64) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '主键ID',
  `style_id` varchar(64) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '款号ID',
  `style_no` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '款号',
  `revision_no` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '修改版本号（如：V1.0, V1.1, V2.0）',
  `revision_type` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '修改类型：MINOR(小改), MAJOR(大改), URGENT(紧急修改)',
  `revision_reason` text COLLATE utf8mb4_unicode_ci COMMENT '修改原因',
  `revision_content` text COLLATE utf8mb4_unicode_ci COMMENT '修改内容详情',
  `before_changes` text COLLATE utf8mb4_unicode_ci COMMENT '修改前信息（JSON格式）',
  `after_changes` text COLLATE utf8mb4_unicode_ci COMMENT '修改后信息（JSON格式）',
  `attachment_urls` text COLLATE utf8mb4_unicode_ci COMMENT '附件URL列表（JSON数组格式）',
  `status` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT 'DRAFT' COMMENT '状态：DRAFT(草稿), SUBMITTED(已提交), APPROVED(已审核), REJECTED(已拒绝), COMPLETED(已完成)',
  `revision_date` date DEFAULT NULL COMMENT '修改日期',
  `expected_complete_date` date DEFAULT NULL COMMENT '预计完成日期',
  `actual_complete_date` date DEFAULT NULL COMMENT '实际完成日期',
  `maintainer_id` varchar(64) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '维护人ID',
  `maintainer_name` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '维护人姓名',
  `maintain_time` datetime DEFAULT NULL COMMENT '维护时间',
  `submitter_id` varchar(64) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '提交人ID',
  `submitter_name` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '提交人姓名',
  `submit_time` datetime DEFAULT NULL COMMENT '提交时间',
  `approver_id` varchar(64) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '审核人ID',
  `approver_name` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '审核人姓名',
  `approval_time` datetime DEFAULT NULL COMMENT '审核时间',
  `approval_comment` text COLLATE utf8mb4_unicode_ci COMMENT '审核意见',
  `pattern_maker_id` varchar(64) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '纸样师傅ID',
  `pattern_maker_name` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '纸样师傅姓名',
  `create_time` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `create_by` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '创建人',
  `update_by` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '更新人',
  `remark` text COLLATE utf8mb4_unicode_ci COMMENT '备注',
  `factory_id` varchar(64) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '工厂ID（多工厂隔离）',
  PRIMARY KEY (`id`),
  KEY `idx_style_no` (`style_no`),
  KEY `idx_style_id` (`style_id`),
  KEY `idx_maintainer` (`maintainer_id`),
  KEY `idx_status` (`status`),
  KEY `idx_revision_date` (`revision_date`),
  KEY `idx_factory_id` (`factory_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='纸样修改记录表 - 记录纸样的修改历史，独立于样板生产数据';
