--
-- Table structure for table `t_production_process_tracking`
--

DROP TABLE IF EXISTS `t_production_process_tracking`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `t_production_process_tracking` (
  `id` varchar(64) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '主键ID（UUID）',
  `production_order_id` varchar(64) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '生产订单ID',
  `production_order_no` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '生产订单号',
  `cutting_bundle_id` varchar(64) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '菲号ID（裁剪扎号ID）',
  `bundle_no` int DEFAULT NULL COMMENT '菲号编号',
  `sku` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'SKU号（styleNo-color-size）',
  `color` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '颜色',
  `size` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '尺码',
  `quantity` int DEFAULT NULL COMMENT '数量（菲号数量）',
  `process_code` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '工序编号（如：sewing, quality）',
  `process_name` varchar(100) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '工序名称（如：车缝、质检）',
  `process_order` int DEFAULT NULL COMMENT '工序顺序（用于排序）',
  `unit_price` decimal(10,2) DEFAULT '0.00' COMMENT '单价（元/件）',
  `scan_status` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT 'pending' COMMENT '扫码状态：pending-待扫码，scanned-已完成，reset-已重置',
  `scan_time` datetime DEFAULT NULL COMMENT '扫码时间',
  `scan_record_id` varchar(64) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '扫码记录ID（关联 t_scan_record）',
  `operator_id` varchar(64) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '操作人ID（扫码人）',
  `operator_name` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '操作人姓名',
  `settlement_amount` decimal(10,2) DEFAULT NULL COMMENT '结算金额（quantity × unit_price）',
  `is_settled` tinyint(1) DEFAULT '0' COMMENT '是否已结算（0-未结算，1-已结算）',
  `settled_at` datetime DEFAULT NULL COMMENT '结算时间',
  `settled_by` varchar(64) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '结算人ID',
  `settled_batch_no` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '结算批次号',
  `creator` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '创建人',
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updater` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '更新人',
  `updated_at` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_bundle_process` (`cutting_bundle_id`,`process_code`) COMMENT '防重复：每个菲号的每个工序只能扫码一次',
  KEY `idx_order_id` (`production_order_id`) COMMENT '订单查询索引',
  KEY `idx_order_no` (`production_order_no`) COMMENT '订单号查询索引',
  KEY `idx_operator` (`operator_id`,`scan_status`) COMMENT '操作人统计索引',
  KEY `idx_settlement` (`is_settled`,`settled_at`) COMMENT '结算状态索引',
  KEY `idx_scan_record` (`scan_record_id`) COMMENT '扫码记录关联索引'
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='生产工序跟踪表（工资结算依据）';
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `t_production_process_tracking`
--

