INSERT INTO `t_style_info` VALUES (1,'STYLE2026010001','春季连衣裙','女装',2026,'SPRING',199.00,15,NULL,'2026æ˜¥å­£æ–°æ¬¾è¿žè¡£è£™','DISABLED','2026-01-22 02:41:47',NULL,'2026-01-22 11:28:35',NULL,NULL,NULL,0,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),(2,'HHY','衬衣','女装',NULL,NULL,0.00,0,NULL,NULL,'DISABLED','2026-01-22 11:36:53',NULL,'2026-01-22 11:37:03',NULL,NULL,NULL,0,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),(3,'HYY2026012212','衬衫','女装',NULL,NULL,55.01,0,'/api/common/download/d86a0d17-fe96-4624-a169-35ff30830412.png','裁剪工艺说明：\n裁剪前需松布和缩水，确认布号、正反面及验布，裁剪按照合同订单数量明细裁剪；\n针织面料需松布24小时后可裁剪，拉布经纬纱向要求经直纬平，注意避开布匹瑕\n裁剪按纸样标注的位置点位、打刀眼对位（特殊面料和款式不可钻孔和打对位刀口），分清各部位不同用料；\n裁片按顺序编号分包，避免大货出现色差现象\n工艺说明：\n.绣花：图案颜色工艺倒顺跟版，花样不可起拱、浮线、断线、漏线、污渍、变形走样，线路过紧，线色有误，线头、纸朴需清理干净，底面需烫布朴，位置参照纸样定位。\n印花:图案需清晰,不可有重影、牙边、粘毛、露底、沙眼、粘手、发亮、龟裂、脱落，掉色,异味、呛鼻等 ，位置参照纸样定位，（胶印大货印花需做防升华处理，包装要放油光纸，防粘）\n工艺：请跟足正确版\n尺寸：请按PatPat提供的纸样与产品生产尺寸表 ,所有成品尺寸必须准确。\n用线及针距要求：全件用402#配色PP线，不可有跳线、浮线、断线疵点 .针距：3cm  14针\n主唛、 洗水唛车法及位置，请参照【PatPat 大货生产服装产品主唛、洗水唛车缝位置规范】。\n整件熨烫平服，无线毛、污渍、油渍、极光及死痕。所有线头必须清理干净。\n按照我司提供的包装与装箱方法进行包装与装箱，制作规范的装箱送货单。','DISABLED','2026-01-22 11:38:53',NULL,'2026-01-22 12:36:22',NULL,NULL,NULL,0,'COMPLETED','2026-01-22 12:09:15',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),(4,'ST2026012200111','衬衫','女装',NULL,'SPRING',41.09,0,'/api/common/download/7ef94e5c-8999-4543-a6d9-b0280db42137.png','裁剪前需松布和缩水，确认布号、正反面及验布，裁剪按照合同订单数量明细裁剪；\n针织面料需松布24小时后可裁剪，拉布经纬纱向要求经直纬平，注意避开布匹瑕疵和色差；\n裁剪按纸样标注的位置点位、打刀眼对位（特殊面料和款式不可钻孔和打对位刀口），分清各部位不同用料；\n裁片按顺序编号分包，避免大货出现色差现象。\n\n绣花：图案颜色工艺倒顺跟PatPat版，花样不可起拱、浮线、断线、漏线、污渍、变形走样，线路过紧，线色有误，线头、纸朴需清理干净，底面需烫布朴，位置参照纸样定位。\n.印花:图案需清晰,不可有重影、牙边、粘毛、露底、沙眼、粘手、发亮、龟裂、脱落，掉色,异味、呛鼻等 ，位置参照纸样定位，（胶印大货印花需做防升华处理，包装要放油光纸