/*!50001 VIEW `v_finished_product_settlement` AS select `po`.`id` AS `order_id`,`po`.`order_no` AS `order_no`,`po`.`status` AS `status`,`po`.`style_no` AS `style_no`,`po`.`factory_id` AS `factory_id`,`po`.`factory_name` AS `factory_name`,`po`.`order_quantity` AS `order_quantity`,`si`.`price` AS `style_final_price`,coalesce(`wh`.`total_warehoused`,0) AS `warehoused_quantity`,coalesce(`wh`.`total_defects`,0) AS `defect_quantity`,coalesce(`wh`.`colors`,'') AS `colors`,coalesce(`mat`.`total_material_cost`,0) AS `material_cost`,coalesce(`scan`.`total_production_cost`,0) AS `production_cost`,(case when (`po`.`order_quantity` > 0) then round((coalesce(`wh`.`total_defects`,0) * ((coalesce(`mat`.`total_material_cost`,0) + coalesce(`scan`.`total_production_cost`,0)) / `po`.`order_quantity`)),2) else 0 end) AS `defect_loss`,round((coalesce(`si`.`price`,0) * coalesce(`wh`.`total_warehoused`,0)),2) AS `total_amount`,round(((((coalesce(`si`.`price`,0) * coalesce(`wh`.`total_warehoused`,0)) - coalesce(`mat`.`total_material_cost`,0)) - coalesce(`scan`.`total_production_cost`,0)) - (case when (`po`.`order_quantity` > 0) then (coalesce(`wh`.`total_defects`,0) * ((coalesce(`mat`.`total_material_cost`,0) + coalesce(`scan`.`total_production_cost`,0)) / `po`.`order_quantity`)) else 0 end)),2) AS `profit`,(case when ((coalesce(`si`.`price`,0) * coalesce(`wh`.`total_warehoused`,0)) > 0) then round(((((((coalesce(`si`.`price`,0) * coalesce(`wh`.`total_warehoused`,0)) - coalesce(`mat`.`total_material_cost`,0)) - coalesce(`scan`.`total_production_cost`,0)) - (case when (`po`.`order_quantity` > 0) then (coalesce(`wh`.`total_defects`,0) * ((coalesce(`mat`.`total_material_cost`,0) + coalesce(`scan`.`total_production_cost`,0)) / `po`.`order_quantity`)) else 0 end)) / (coalesce(`si`.`price`,0) * coalesce(`wh`.`total_warehoused`,0))) * 100),2) else 0 end) AS `profit_margin`,`po`.`create_time` AS `create_time`,`po`.`update_time` AS `update_time` from ((((`t_production_order` `po` left join `t_style_info` `si` on((`po`.`style_no` = `si`.`style_no`))) left join (select `pw`.`order_no` AS `order_no`,sum((case when (`pw`.`quality_status` = 'QUALIFIED') then `pw`.`warehousing_quantity` else 0 end)) AS `total_warehoused`,sum((case when (`pw`.`quality_status` in ('UNQUALIFIED','DEFECTIVE')) then `pw`.`warehousing_quantity` else 0 end)) AS `total_defects`,group_concat(distinct (case when (`cb`.`color` is not null) then `cb`.`color` else '' end) order by `cb`.`color` ASC separator ', ') AS `colors` from (`t_product_warehousing` `pw` left join `t_cutting_bundle` `cb` on((`pw`.`cutting_bundle_id` = `cb`.`id`))) group by `pw`.`order_no`) `wh` on((`po`.`order_no` = `wh`.`order_no`))) left join (select `t_material_purchase`.`order_no` AS `order_no`,sum(`t_material_purchase`.`total_amount`) AS `total_material_cost` from `t_material_purchase` where (`t_material_purchase`.`status` in ('RECEIVED','COMPLETED')) group by `t_material_purchase`.`order_no`) `mat` on((`po`.`order_no` = `mat`.`order_no`))) left join (select `t_scan_record`.`order_no` AS `order_no`,sum(`t_scan_record`.`scan_cost`) AS `total_production_cost` from `t_scan_record` where (`t_scan_record`.`scan_cost` is not null) group by `t_scan_record`.`order_no`) `scan` on((`po`.`order_no` = `scan`.`order_no`))) order by `po`.`create_time` desc */;
